1	//! Single source of truth for every settable config key across
2	//! vc-x1's two config homes (the user config file and the
3	//! per-repo workspace config).
4	//!
5	//! - `crate::config_cmd` prints this registry as an annotated
6	//!   schema, and — with `--validate` — checks a config file's keys
7	//!   against it (dynamic-segment aware).
8	//! - `crate::init` derives init's commented defaults from
9	//!   `schema()`, so these surfaces cannot drift from this list.
10	
11	/// Which config home a key belongs to.
12	/// - `User` — `~/.config/vc-x1/config.toml`
13	/// - `WorkspaceCode` / `WorkspaceBot` — `<root>/.vc-config.toml`
14	///   in the work repo vs the `.claude` bot repo
15	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
16	pub enum Home {
17	    User,
18	    WorkspaceCode,
19	    WorkspaceBot,
20	}
21	
22	/// The value shape a key expects (for rendering / future typed
23	/// use).
24	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
25	pub enum ValueKind {
26	    Str,
27	    Usize,
28	    ItemList,
29	}
30	
31	/// One settable configuration key.
32	pub struct ConfigKey {
33	    /// The config key (TOML table and key joined by `.`), e.g.
34	    /// `"bot-session.col-width"`.
35	    pub path: &'static str,
36	    /// Which home(s) accept this key.
37	    pub homes: &'static [Home],
38	    /// The value shape this key expects.
39	    pub kind: ValueKind,
40	    /// Rendered default, `None` if there is no default.
41	    pub default: Option<&'static str>,
42	    /// Active (not commented) in init; the value is role-specific.
43	    pub required: bool,
44	    /// The path has a `<placeholder>` segment matching a family
45	    /// of keys (e.g. `repo.category.<cat>`).
46	    pub dynamic: bool,
47	    /// One-line description.
48	    pub doc: &'static str,
49	    /// The command/flag or structural context this key is
50	    /// associated with (e.g. `"bot-session --col-width"`).
51	    pub used_by: &'static str,
52	}
53	
54	/// Homes accepted by every `bot-session.*` key: all three homes,
55	/// since the user config and both workspace configs may each
56	/// carry a default.
57	const BOT_SESSION_HOMES: &[Home] = &[Home::User, Home::WorkspaceCode, Home::WorkspaceBot];
58	
59	/// Homes accepted by workspace-only keys (`workspace.*`,
60	/// `push.*`): the two `.vc-config.toml` homes, never the user
61	/// config.
62	const WORKSPACE_HOMES: &[Home] = &[Home::WorkspaceCode, Home::WorkspaceBot];
63	
64	/// The complete registry of settable keys.
65	///
66	/// - User home: `default.*`, `repo.*`, and the per-account
67	///   `account.<name>.repo.*` family.
68	/// - `bot-session.*`: accepted in all three homes.
69	/// - Workspace-only: `workspace.*`, `push.*`.
70	const SCHEMA: &[ConfigKey] = &[
71	    ConfigKey {
72	        path: "default.account",
73	        homes: &[Home::User],
74	        kind: ValueKind::Str,
75	        default: None,
76	        required: false,
77	        dynamic: false,
78	        doc: "Default account when --account is absent",
79	        used_by: "--account (init and account-aware commands)",
80	    },
81	    ConfigKey {
82	        path: "default.debug",
83	        homes: &[Home::User],
84	        kind: ValueKind::Str,
85	        default: None,
86	        required: false,
87	        dynamic: false,
88	        doc: "Default --debug value when used without an argument (reserved; not yet consumed)",
89	        used_by: "--debug (reserved; not yet consumed)",
90	    },
91	    ConfigKey {
92	        path: "repo.default",
93	        homes: &[Home::User],
94	        kind: ValueKind::Str,
95	        default: None,
96	        required: false,
97	        dynamic: false,
98	        doc: "Top-level shorthand: repo category to use when --repo is absent",
99	        used_by: "--repo (default category when --repo is bare)",
100	    },
101	    ConfigKey {
102	        path: "repo.category.<cat>",
103	        homes: &[Home::User],
104	        kind: ValueKind::Str,
105	        default: None,
106	        required: false,
107	        dynamic: true,
108	        doc: "Top-level shorthand: literal value for repo category <cat>",
109	        used_by: "--repo <cat> (init remote/local resolution)",
110	    },
111	    ConfigKey {
112	        path: "account.<name>.repo.default",
113	        homes: &[Home::User],
114	        kind: ValueKind::Str,
115	        default: None,
116	        required: false,
117	        dynamic: true,
118	        doc: "Per-account default repo category",
119	        used_by: "--account <name> with --repo",
120	    },
121	    ConfigKey {
122	        path: "account.<name>.repo.category.<cat>",
123	        homes: &[Home::User],
124	        kind: ValueKind::Str,
125	        default: None,
126	        required: false,
127	        dynamic: true,
128	        doc: "Per-account literal value for repo category <cat>",
129	        used_by: "--account <name> with --repo <cat>",
130	    },
131	    ConfigKey {
132	        path: "bot-session.items",
133	        homes: BOT_SESSION_HOMES,
134	        kind: ValueKind::ItemList,
135	        default: Some("headers,user,assistant,tool,summary"),
136	        required: false,
137	        dynamic: false,
138	        doc: "Default bot-session item set (comma-separated)",
139	        used_by: "bot-session --<item> / --no-<item> / --all / --none",
140	    },
141	    ConfigKey {
142	        path: "bot-session.result-lines",
143	        homes: BOT_SESSION_HOMES,
144	        kind: ValueKind::Usize,
145	        default: Some("10"),
146	        required: false,
147	        dynamic: false,
148	        doc: "Default --result-lines: max lines shown per tool result (0 = unlimited)",
149	        used_by: "bot-session --result-lines",
150	    },
151	    ConfigKey {
152	        path: "bot-session.col-width",
153	        homes: BOT_SESSION_HOMES,
154	        kind: ValueKind::Usize,
155	        default: Some("68"),
156	        required: false,
157	        dynamic: false,
158	        doc: "Default --col-width: first-column width in the field-inventory views",
159	        used_by: "bot-session --col-width",
160	    },
161	    ConfigKey {
162	        path: "workspace.path",
163	        homes: WORKSPACE_HOMES,
164	        kind: ValueKind::Str,
165	        default: None,
166	        required: true,
167	        dynamic: false,
168	        doc: "This repo's path relative to the workspace root (role-specific: \"/\" for the work repo, \"/.claude\" for the bot repo)",
169	        used_by: "find_workspace_root, sync, push, validate-desc (structural; written by init)",
170	    },
171	    ConfigKey {
172	        path: "workspace.other-repo",
173	        homes: WORKSPACE_HOMES,
174	        kind: ValueKind::Str,
175	        default: None,
176	        required: false,
177	        dynamic: false,
178	        doc: "Relative path to the counterpart repo; presence signals dual-repo mode (role-specific: \".claude\" for the work repo, \"..\" for the bot repo)",
179	        used_by: "default_scope, validate-desc/fix-desc --other-repo (structural)",
180	    },
181	    ConfigKey {
182	        path: "push.state-dir",
183	        homes: WORKSPACE_HOMES,
184	        kind: ValueKind::Str,
185	        default: Some(".vc-x1"),
186	        required: false,
187	        dynamic: false,
188	        doc: "Directory (relative to repo root) holding the push state file",
189	        used_by: "push / squash-push (state-file directory)",
190	    },
191	    ConfigKey {
192	        path: "push.state-file",
193	        homes: WORKSPACE_HOMES,
194	        kind: ValueKind::Str,
195	        default: Some("push-state.toml"),
196	        required: false,
197	        dynamic: false,
198	        doc: "Filename of the push state file under push.state-dir",
199	        used_by: "push / squash-push (state-file name)",
200	    },
201	];
202	
203	/// Returns the complete registry of settable config keys.
204	pub fn schema() -> &'static [ConfigKey] {
205	    SCHEMA
206	}
207	
208	/// Split a config key on its last `.` into `(section, leaf)`.
209	///
210	/// A path with no `.` (none exist in the current schema) falls
211	/// back to an empty section so the key still renders under a
212	/// blank `[]` header rather than panicking.
213	pub fn section_and_leaf(path: &str) -> (&str, &str) {
214	    match path.rfind('.') {
215	        Some(idx) => (&path[..idx], &path[idx + 1..]),
216	        None => ("", path),
217	    }
218	}
219	
220	/// Render a key's value cell: the quoted/bare default, or an
221	/// angle-bracket placeholder by kind when there is no default —
222	/// except a required key with no default, which renders
223	/// `<required>` so it stands out.
224	pub fn render_value(key: &ConfigKey) -> String {
225	    match key.default {
226	        Some(d) => match key.kind {
227	            ValueKind::Usize => d.to_string(),
228	            ValueKind::Str | ValueKind::ItemList => format!("{d:?}"),
229	        },
230	        None => {
231	            if key.required {
232	                "<required>".to_string()
233	            } else {
234	                match key.kind {
235	                    ValueKind::Str => "<str>".to_string(),
236	                    ValueKind::Usize => "<usize>".to_string(),
237	                    ValueKind::ItemList => "<items>".to_string(),
238	                }
239	            }
240	        }
241	    }
242	}
243	
244	/// Render a key's `default:` note: the quoted/bare default, or a
245	/// parenthetical explaining the absence — `(required; ...)` for a
246	/// required key with no default (role-specific, filled by init),
247	/// `(none)` otherwise.
248	fn render_default_note(key: &ConfigKey) -> String {
249	    match key.default {
250	        Some(d) => match key.kind {
251	            ValueKind::Usize => d.to_string(),
252	            ValueKind::Str | ValueKind::ItemList => format!("{d:?}"),
253	        },
254	        None => {
255	            if key.required {
256	                "(required; role-specific — see init)".to_string()
257	            } else {
258	                "(none)".to_string()
259	            }
260	        }
261	    }
262	}
263	
264	/// Word-wrap `text` into `#`-prefixed lines, `first_prefix` on the
265	/// first line and `cont_prefix` on continuations, each kept to
266	/// `width` columns where possible (a single word longer than
267	/// `width` still gets its own line, unsplit).
268	fn wrap_hash_comment(text: &str, first_prefix: &str, cont_prefix: &str, width: usize) -> String {
269	    let mut lines: Vec<String> = Vec::new();
270	    let mut current = String::new();
271	    for word in text.split_whitespace() {
272	        let prefix_len = if lines.is_empty() {
273	            first_prefix.len()
274	        } else {
275	            cont_prefix.len()
276	        };
277	        let sep = usize::from(!current.is_empty());
278	        let tentative_len = prefix_len + current.len() + sep + word.len();
279	        if !current.is_empty() && tentative_len > width {
280	            lines.push(std::mem::take(&mut current));
281	        }
282	        if !current.is_empty() {
283	            current.push(' ');
284	        }
285	        current.push_str(word);
286	    }
287	    if !current.is_empty() {
288	        lines.push(current);
289	    }
290	    let mut out = String::new();
291	    for (i, l) in lines.iter().enumerate() {
292	        let prefix = if i == 0 { first_prefix } else { cont_prefix };
293	        out.push_str(prefix);
294	        out.push_str(l);
295	        out.push('\n');
296	    }
297	    out
298	}
299	
300	/// Render one key as a thorough, self-documenting doc-block:
301	/// - `# <path> — <doc>` (word-wrapped onto `#   ...`
302	///   continuations past ~72 cols),
303	/// - `#   used by: <used_by>`,
304	/// - `#   default: <rendered default, or a "(none)"/"(required...)"
305	///   note>`,
306	/// - the assignment line itself — uncommented for a `required` key
307	///   (init fills in the role-specific value), commented (`# `)
308	///   otherwise, with the rendered default or a kind placeholder
309	///   (`<str>` etc.) when there is no default,
310	/// - a trailing blank line, so consecutive blocks read as
311	///   paragraph-separated entries.
312	///
313	/// Shared by `crate::config_cmd` (printed schema) and `crate::init`
314	/// (commented defaults in the generated `.vc-config.toml`) so the
315	/// two surfaces cannot drift from each other's wording.
316	pub fn render_key_block(key: &ConfigKey) -> String {
317	    let mut out = String::new();
318	    let header_text = format!("{} — {}", key.path, key.doc);
319	    out.push_str(&wrap_hash_comment(&header_text, "# ", "#   ", 72));
320	    out.push_str(&format!("#   used by: {}\n", key.used_by));
321	    out.push_str(&format!("#   default: {}\n", render_default_note(key)));
322	    let (_section, leaf) = section_and_leaf(key.path);
323	    let prefix = if key.required { "" } else { "# " };
324	    let value = render_value(key);
325	    out.push_str(&format!("{prefix}{leaf} = {value}\n"));
326	    out.push('\n');
327	    out
328	}
329	
330	#[cfg(test)]
331	mod tests {
332	    use super::*;
333	
334	    /// Finds a schema entry by its config key.
335	    ///
336	    /// - Panics if not found: tests only, and a missing key is a
337	    ///   test bug worth failing loudly on.
338	    #[allow(clippy::unwrap_used, clippy::expect_used)]
339	    fn find(path: &str) -> &'static ConfigKey {
340	        schema()
341	            .iter()
342	            .find(|k| k.path == path)
343	            .unwrap_or_else(|| panic!("schema key {path:?} not found"))
344	    }
345	
346	    #[test]
347	    fn defaults_match_source_consts() {
348	        assert_eq!(
349	            find("bot-session.col-width").default,
350	            Some(crate::bot_session::COL_WIDTH.to_string()).as_deref()
351	        );
352	        assert_eq!(
353	            find("bot-session.result-lines").default,
354	            Some(crate::bot_session::RESULT_LINE_CAP.to_string()).as_deref()
355	        );
356	        assert_eq!(
357	            find("push.state-dir").default,
358	            Some(crate::push::DEFAULT_STATE_DIR)
359	        );
360	        assert_eq!(
361	            find("push.state-file").default,
362	            Some(crate::push::DEFAULT_STATE_FILE)
363	        );
364	    }
365	
366	    #[test]
367	    fn paths_unique() {
368	        let mut paths: Vec<&str> = schema().iter().map(|k| k.path).collect();
369	        paths.sort_unstable();
370	        let mut deduped = paths.clone();
371	        deduped.dedup();
372	        assert_eq!(paths.len(), deduped.len(), "duplicate path(s) in schema()");
373	    }
374	
375	    #[test]
376	    fn homes_non_empty() {
377	        for key in schema() {
378	            assert!(!key.homes.is_empty(), "{} has no homes", key.path);
379	        }
380	    }
381	
382	    #[test]
383	    fn dynamic_keys_have_placeholder() {
384	        for key in schema() {
385	            let has_placeholder = key.path.contains('<');
386	            assert_eq!(
387	                key.dynamic, has_placeholder,
388	                "{}: dynamic={} but placeholder-presence={}",
389	                key.path, key.dynamic, has_placeholder
390	            );
391	        }
392	    }
393	}
